CREATE OR REPLACE FUNCTION OFSERM.PC_CREDIT_DERIVATIVES_POPULATION(
    P_V_BATCH_ID         VARCHAR2,
    P_V_MIS_DATE         VARCHAR2,
    P_V_RUN_ID           VARCHAR2,
    P_V_PROCESS_ID       VARCHAR2,
    P_V_RUN_EXECUTION_ID VARCHAR2,
    P_N_RUN_SKEY         VARCHAR2,
    P_V_TASK_ID          VARCHAR2
) RETURN VARCHAR2 AUTHID CURRENT_USER AS

    ld_mis_date   DATE          := TO_DATE(P_V_MIS_DATE, 'YYYYMMDD');
    ln_mis_date   NUMBER        := TO_NUMBER(P_V_MIS_DATE);
    ln_run_skey   NUMBER(5)     := TO_NUMBER(SUBSTR(P_N_RUN_SKEY, 8, LENGTH(P_N_RUN_SKEY)));
    lv_run_id     VARCHAR2(64)  := SUBSTR(P_V_RUN_ID, 8, LENGTH(P_V_RUN_ID));

BEGIN

    insert /*+APPEND*/ into FCT_MARKET_RISK_EXPOSURES(D_MATURITY_DATE,D_REPRICING_DATE,F_GMR_INDICATOR,N_ACCT_SKEY,N_COUNTRY_SKEY,N_COUPON_FREQ_PAY,N_COUPON_FREQ_RCV,N_COUPON_PAY,N_COUPON_RCV,N_INSTR_TYPE_SKEY,N_POST_OFFSET_EXP_AMT,N_POSITION_SKEY,N_SPECIFIC_RISK_CHARGE,N_SPECIFIC_RISK_WEIGHT,V_BUY_REC_CCY_CODE,V_SELL_PAY_CCY_CODE,D_CONTRACT_START_DATE,F_CAPITAL_CHARGE_EXCLUSION,F_OTC_INDICATOR,F_SECURITIZED_FLAG,N_CONTRACT_ACCT_SKEY,N_BANK_BASE_ROLE_SKEY,N_BASEL_METHOD_SKEY,N_BASEL_RATING,N_BUSINESS_UNIT_SKEY,N_CUST_CRAR_PERCENT,N_CUST_SKEY,N_ENTITY_SKEY,N_GAAP_SKEY,N_IRC_BENCHMARK_SKEY,N_ISSUE_SKEY,N_LEG_REP_SKEY,N_MARKET_CENTRE_SKEY,N_MIS_DATE_SKEY,N_MR_ISSUER_TYPE_SKEY,N_ORIGINAL_MATURITY,N_REF_INDEX_SKEY,N_REG_CAP_PARTCP_VALUE,N_RUN_SKEY,N_SEC_POOL_TYPE_SKEY,N_STD_UNIT_SKEY,N_STRIKE_PRICE,V_CCY_CODE,V_EXP_CATEGORY_CODE,V_EXP_RCY_CODE,N_CURR_MKT_PRICE,N_INSTRUMENT_SKEY,N_CONTRACT_SIZE,N_PAR_VALUE,V_DAY_COUNTER,N_RUN_PARAMETER_SETUP_SKEY)SELECT  /*+PARALLEL (4)*/ CASE WHEN DIM_INSTRUMENT_TYPE.v_instr_type_code = 'IRSPOTCLN' THEN FCT_MARKET_RISK_EXPOSURES.d_maturity_date END,CASE WHEN NOT( MR_INSTRUMENT_POSITION_MAPPING.v_mr_instr_type_code = 'IRSWAPTRS' AND MR_INSTRUMENT_POSITION_MAPPING.v_instr_pos_code = MR_INSTRUMENT_POSITION_MAPPING.v_pc_pos_code ) THEN ADD_MONTHS(FCT_UNDERLYING_DTL.d_issue_date, TRUNC(MONTHS_BETWEEN(DIM_DATES.D_CALENDAR_DATE, FCT_UNDERLYING_DTL.d_issue_date)/ FCT_UNDERLYING_DTL.n_coupon_freq )*FCT_UNDERLYING_DTL.n_coupon_freq ) END,CASE WHEN DIM_INSTRUMENT_TYPE.v_instr_type_code IN ('IRSWAPCDS','IRSWAPBCDS') THEN 'N' WHEN (DIM_INSTRUMENT_TYPE.v_instr_type_code = 'IRSPOTCLN' AND DIM_MR_SP_RW_CATEGORY.v_category_code <> 'OTH' AND MR_INSTRUMENT_POSITION_MAPPING.v_pc_pos_seq = 1) THEN 'Y' WHEN (DIM_INSTRUMENT_TYPE.v_instr_type_code = 'IRSPOTCLN' AND MR_INSTRUMENT_POSITION_MAPPING.v_pc_pos_seq > 1) THEN 'N' END,(SELECT MIN(DIM_EXPOSURE.n_acct_skey) FROM DIM_EXPOSURE WHERE DIM_EXPOSURE.n_contract_acct_skey = FCT_MARKET_RISK_EXPOSURES.n_acct_skey AND DIM_DATES.D_CALENDAR_DATE between DIM_EXPOSURE.d_record_start_date and DIM_EXPOSURE.d_record_end_date) + ROW_NUMBER() OVER (PARTITION BY FCT_MARKET_RISK_EXPOSURES.n_acct_skey ORDER BY FCT_MARKET_RISK_EXPOSURES.n_acct_skey) - 1,COALESCE(FCT_MARKET_RISK_EXPOSURES.N_COUNTRY_SKEY,0),CASE WHEN( DIM_INSTRUMENT_TYPE.v_instr_type_code = 'IRSPOTCLN' AND DIM_MR_SP_RW_CATEGORY.v_category_code = 'OTH' AND MR_INSTRUMENT_POSITION_MAPPING.v_pc_pos_seq > 1 ) THEN FCT_UNDERLYING_DTL.n_coupon_freq WHEN ( DIM_INSTRUMENT_TYPE.v_instr_type_code = 'IRSPOTCLN' ) THEN FCT_MARKET_RISK_EXPOSURES.n_coupon_freq_rcv END,CASE WHEN ( DIM_INSTRUMENT_TYPE.v_instr_type_code = 'IRSPOTCLN' AND DIM_MR_SP_RW_CATEGORY.v_category_code = 'OTH' AND MR_INSTRUMENT_POSITION_MAPPING.v_pc_pos_seq > 1 ) THEN FCT_UNDERLYING_DTL.n_coupon_freq WHEN ( DIM_INSTRUMENT_TYPE.v_instr_type_code = 'IRSPOTCLN' ) THEN FCT_MARKET_RISK_EXPOSURES.n_coupon_freq_pay END,CASE WHEN ( DIM_INSTRUMENT_TYPE.v_instr_type_code = 'IRSPOTCLN' AND DIM_MR_SP_RW_CATEGORY.v_category_code = 'OTH' AND MR_INSTRUMENT_POSITION_MAPPING.v_pc_pos_seq > 1 ) THEN FCT_UNDERLYING_DTL.n_coupon WHEN ( DIM_INSTRUMENT_TYPE.v_instr_type_code = 'IRSPOTCLN' ) THEN FCT_MARKET_RISK_EXPOSURES.n_coupon_pay END,CASE WHEN ( DIM_INSTRUMENT_TYPE.v_instr_type_code = 'IRSPOTCLN' AND DIM_MR_SP_RW_CATEGORY.v_category_code = 'OTH' AND MR_INSTRUMENT_POSITION_MAPPING.v_pc_pos_seq > 1 ) THEN FCT_UNDERLYING_DTL.n_coupon WHEN ( DIM_INSTRUMENT_TYPE.v_instr_type_code = 'IRSPOTCLN') THEN FCT_MARKET_RISK_EXPOSURES.n_coupon_rcv END,CASE WHEN DIM_INSTRUMENT_TYPE.v_instr_type_code = 'IRSPOTCLN' THEN (SELECT n_instr_type_skey FROM DIM_INSTRUMENT_TYPE WHERE DIM_INSTRUMENT_TYPE.v_instr_type_code = 'IRSPOTFIB'AND to_date('20260331','YYYYMMDD') BETWEEN DIM_INSTRUMENT_TYPE.D_RECORD_START_DATE AND DIM_INSTRUMENT_TYPE.D_RECORD_END_DATE) END,CASE WHEN ( DIM_INSTRUMENT_TYPE.v_instr_type_code = 'IRSPOTCLN' AND DIM_MR_SP_RW_CATEGORY.v_category_code = 'OTH' AND MR_INSTRUMENT_POSITION_MAPPING.v_pc_pos_seq = 1 ) THEN FCT_MARKET_RISK_EXPOSURES.n_curr_mkt_price WHEN ( DIM_INSTRUMENT_TYPE.v_instr_type_code = 'IRSPOTCLN' AND DIM_MR_SP_RW_CATEGORY.v_category_code = 'OTH' AND MR_INSTRUMENT_POSITION_MAPPING.v_pc_pos_seq > 1 ) THEN FCT_UNDERLYING_DTL.n_par_value WHEN ( DIM_INSTRUMENT_TYPE.v_instr_type_code = 'IRSPOTCLN' AND DIM_MR_SP_RW_CATEGORY.v_category_code <> 'OTH' AND MR_INSTRUMENT_POSITION_MAPPING.v_pc_pos_seq = 1 ) THEN FCT_MARKET_RISK_EXPOSURES.n_curr_mkt_price END,(SELECT d.n_position_skey FROM DIM_MARKET_RISK_POSITION d WHERE d.v_position_code = MR_INSTRUMENT_POSITION_MAPPING.v_pc_pos_code AND to_date('20260331','YYYYMMDD') BETWEEN d.D_RECORD_START_DATE AND d.D_RECORD_END_DATE),CASE WHEN FCT_MARKET_RISK_EXPOSURES.N_SPECIFIC_RISK_CHARGE IS NOT NULL AND ( MR_INSTRUMENT_POSITION_MAPPING.V_MR_INSTR_TYPE_CODE = 'IRSWAPTRS' AND MR_INSTRUMENT_POSITION_MAPPING.V_INSTR_POS_CODE <> MR_INSTRUMENT_POSITION_MAPPING.V_PC_POS_CODE ) THEN FCT_MARKET_RISK_EXPOSURES.N_SPECIFIC_RISK_CHARGE END,CASE WHEN DIM_INSTRUMENT_TYPE.v_instr_type_code = 'IRSWAPTRS' THEN FCT_UNDERLYING_DTL.n_specific_risk_weight WHEN DIM_INSTRUMENT_TYPE.v_instr_type_code = 'IRSPOTCLN' THEN CASE WHEN DIM_MR_SP_RW_CATEGORY.V_CATEGORY_CODE <> 'OTH' THEN FCT_UNDERLYING_DTL.n_specific_risk_weight ELSE FCT_MARKET_RISK_EXPOSURES.n_specific_risk_weight END WHEN FCT_MARKET_RISK_EXPOSURES.n_basel_rating IS NOT NULL THEN FCT_MARKET_RISK_EXPOSURES.n_specific_risk_weight ELSE FCT_UNDERLYING_DTL.n_specific_risk_weight END,CASE WHEN MR_INSTRUMENT_POSITION_MAPPING.v_pc_pos_code = 'LONG' THEN FCT_UNDERLYING_DTL.v_ccy_code END,CASE WHEN MR_INSTRUMENT_POSITION_MAPPING.v_pc_pos_code = 'SHORT' THEN FCT_UNDERLYING_DTL.v_ccy_code END,FCT_MARKET_RISK_EXPOSURES.D_CONTRACT_START_DATE,FCT_MARKET_RISK_EXPOSURES.F_CAPITAL_CHARGE_EXCLUSION,FCT_MARKET_RISK_EXPOSURES.F_OTC_INDICATOR,FCT_MARKET_RISK_EXPOSURES.F_SECURITIZED_FLAG,to_char(FCT_MARKET_RISK_EXPOSURES.N_ACCT_SKEY),to_char(FCT_MARKET_RISK_EXPOSURES.N_BANK_BASE_ROLE_SKEY),to_char(FCT_MARKET_RISK_EXPOSURES.N_BASEL_METHOD_SKEY),to_char(FCT_MARKET_RISK_EXPOSURES.N_BASEL_RATING),to_char(FCT_MARKET_RISK_EXPOSURES.N_BUSINESS_UNIT_SKEY),to_char(FCT_MARKET_RISK_EXPOSURES.N_CUST_CRAR_PERCENT),to_char(FCT_MARKET_RISK_EXPOSURES.N_CUST_SKEY),to_char(FCT_MARKET_RISK_EXPOSURES.N_ENTITY_SKEY),to_char(FCT_MARKET_RISK_EXPOSURES.N_GAAP_SKEY),to_char(FCT_MARKET_RISK_EXPOSURES.N_IRC_BENCHMARK_SKEY),to_char(FCT_MARKET_RISK_EXPOSURES.N_ISSUE_SKEY),to_char(FCT_MARKET_RISK_EXPOSURES.N_LEG_REP_SKEY),to_char(FCT_MARKET_RISK_EXPOSURES.N_MARKET_CENTRE_SKEY),to_char(FCT_MARKET_RISK_EXPOSURES.N_MIS_DATE_SKEY),to_char(FCT_MARKET_RISK_EXPOSURES.N_MR_ISSUER_TYPE_SKEY),to_char(FCT_MARKET_RISK_EXPOSURES.N_ORIGINAL_MATURITY),to_char(FCT_MARKET_RISK_EXPOSURES.N_REF_INDEX_SKEY),to_char(FCT_MARKET_RISK_EXPOSURES.N_REG_CAP_PARTCP_VALUE),to_char(FCT_MARKET_RISK_EXPOSURES.N_RUN_SKEY),to_char(FCT_MARKET_RISK_EXPOSURES.N_SEC_POOL_TYPE_SKEY),to_char(FCT_MARKET_RISK_EXPOSURES.N_STD_UNIT_SKEY),to_char(FCT_MARKET_RISK_EXPOSURES.N_STRIKE_PRICE),FCT_MARKET_RISK_EXPOSURES.V_CCY_CODE,FCT_MARKET_RISK_EXPOSURES.V_EXP_CATEGORY_CODE,FCT_MARKET_RISK_EXPOSURES.V_EXP_RCY_CODE,to_char(FCT_UNDERLYING_DTL.N_CURR_MKT_VALUE),to_char(FCT_UNDERLYING_DTL.N_INSTRUMENT_SKEY),to_char(FCT_UNDERLYING_DTL.N_OUTSTANDING_UNITS),to_char(FCT_UNDERLYING_DTL.N_PAR_VALUE),FCT_UNDERLYING_DTL.V_DAY_COUNTER,to_char(RUN_PARAMETERS.N_RUN_PARAMETER_SETUP_SKEY) FROM FCT_MARKET_RISK_EXPOSURES INNER JOIN DIM_RUN ON FCT_MARKET_RISK_EXPOSURES.N_RUN_SKEY = DIM_RUN.N_RUN_SKEY AND DIM_RUN.N_RUN_SKEY = '870' INNER JOIN DIM_DATES ON FCT_MARKET_RISK_EXPOSURES.N_MIS_DATE_SKEY = DIM_DATES.N_DATE_SKEY AND DIM_DATES.D_CALENDAR_DATE = to_date('20260331','YYYYMMDD') LEFT OUTER JOIN FCT_UNDERLYING_DTL ON FCT_MARKET_RISK_EXPOSURES.N_ACCT_SKEY = FCT_UNDERLYING_DTL.N_CONTRACT_ACCT_SKEY AND FCT_MARKET_RISK_EXPOSURES.N_RUN_SKEY = FCT_UNDERLYING_DTL.N_RUN_SKEY AND FCT_MARKET_RISK_EXPOSURES.N_MIS_DATE_SKEY = FCT_UNDERLYING_DTL.N_MIS_DATE_SKEY INNER JOIN DIM_INSTRUMENT_TYPE ON FCT_MARKET_RISK_EXPOSURES.N_INSTR_TYPE_SKEY = DIM_INSTRUMENT_TYPE.N_INSTR_TYPE_SKEY INNER JOIN DIM_MARKET_RISK_POSITION ON FCT_MARKET_RISK_EXPOSURES.N_POSITION_SKEY = DIM_MARKET_RISK_POSITION.N_POSITION_SKEY INNER JOIN MR_INSTRUMENT_POSITION_MAPPING ON ( DIM_INSTRUMENT_TYPE.V_INSTR_TYPE_CODE = MR_INSTRUMENT_POSITION_MAPPING.V_MR_INSTR_TYPE_CODE AND MR_INSTRUMENT_POSITION_MAPPING.V_INSTR_POS_CODE = DIM_MARKET_RISK_POSITION.V_POSITION_CODE ) OR ( DIM_INSTRUMENT_TYPE.V_INSTR_TYPE_CODE = MR_INSTRUMENT_POSITION_MAPPING.V_MR_INSTR_TYPE_CODE AND MR_INSTRUMENT_POSITION_MAPPING.V_INSTR_POS_CODE IS NULL ) LEFT OUTER JOIN DIM_MR_SP_RW_CATEGORY ON FCT_MARKET_RISK_EXPOSURES.N_CATEGORY_SKEY = DIM_MR_SP_RW_CATEGORY.N_CATEGORY_SKEY LEFT OUTER JOIN FSI_CAP_RUN_EXE_PARAMETERS ON FSI_CAP_RUN_EXE_PARAMETERS.N_RUN_SKEY = '870' LEFT OUTER JOIN FSI_BASEL_EXEC_APPR_DETAILS ON FSI_BASEL_EXEC_APPR_DETAILS.N_RUN_SKEY = '870' AND FSI_BASEL_EXEC_APPR_DETAILS.V_RISK_SUB_TYPE = 'MR' LEFT OUTER JOIN RUN_PARAMETERS ON RUN_PARAMETERS.N_RUN_SKEY = '870' AND FSI_BASEL_EXEC_APPR_DETAILS.N_RUN_PARAMETER_SKEY = RUN_PARAMETERS.N_RUN_PARAMETER_SKEY INNER JOIN FSI_CAP_APPROACH_TYPE_MASTER ON FSI_CAP_APPROACH_TYPE_MASTER.V_APPROACH_TYPE = FSI_BASEL_EXEC_APPR_DETAILS.V_APPROACH_TYPE_CODE WHERE 1=1 AND 1=1 AND ( ( DIM_INSTRUMENT_TYPE.v_instr_type_code = 'IRSPOTCLN' AND DIM_MR_SP_RW_CATEGORY.v_category_code <> 'OTH' AND MR_INSTRUMENT_POSITION_MAPPING.v_pc_pos_seq = 1 ) OR ( DIM_INSTRUMENT_TYPE.v_instr_type_code = 'IRSPOTCLN' AND DIM_MR_SP_RW_CATEGORY.v_category_code = 'OTH' ) OR ( DIM_INSTRUMENT_TYPE.v_instr_type_code IN ( 'IRSWAPCDS' ,'IRSWAPTRS' /*,'IRSWAPBCDS'*/ ) ) ) LOG ERRORS INTO FCT_MARKET_RISK_EXPOSURES$ ('1776768930247_57791020_20260331_1_Job_43dd468690074522a88e3cab46275311') REJECT LIMIT 0;

    COMMIT;
    RETURN 'OK';

EXCEPTION
    WHEN OTHERS THEN
        ROLLBACK;
        RETURN 'FAIL: ' || SQLERRM;
END;
